function applyVisualFlags(html, data) {
  if (!html) return html;

  if (!flagEnabled(data, 'include_summary', true)) {
    for (const marker of [
      'Resumen ejecutivo',
      'TOTAL ACTIVOS',
      'TOTAL CON CONTACTO',
      'TOTAL TICKETS',
      'TOTAL CAMBIOS',
      'TOTAL MOVIMIENTOS',
    ]) {
      html = removeAllRowsByMarker(html, marker);
    }
  }

  if (!flagEnabled(data, 'include_detail', true)) {
    for (const marker of [
      'Detalle operacional',
      'Detalle de activos',
      'Detalle de tickets',
      'Detalle por agente',
      'Detalle por antig?edad',
