  return html;
}

function normalizeEmail(value) {
  const text = String(value ?? '').trim();
  const match = text.match(/[A-Z0-9._%+-]+@[A-Z0-9.-]+\.[A-Z]{2,}/i);
  return match ? match[0].toLowerCase() : '';
}

return $input.all().map((item) => {
  const configReporte = getNodeJson('Config Reporte');
  const setMixed = getNodeJson('SetMixed - Configuracion efectiva');
  const setTrigger = getNodeJson('SetTrigger - Flujo');
  const itemJson = item.json || {};

  /*
   * Orden correcto:
   * 1. ConfiguraciÃ³n base
   * 2. Trigger
   * 3. ConfiguraciÃ³n efectiva
   * 4. Item actual ya procesado por agente
   *
   * El item actual debe quedar al final para que email_to, agent_email,
   * agent_name y email_subject no sean sobrescritos por defaults globales.
   */
  const flags = mergeFlags(configReporte, setTrigger, setMixed, itemJson);

  const data = {
    ...configReporte,
    ...setTrigger,
    ...setMixed,
    ...itemJson,
    flags,
  };

  for (const [key, value] of Object.entries(flags)) {
    data[key] = value;
  }

  /*
   * Blindaje explÃ­cito de destinatarios dinÃ¡micos.
   * Esto evita que email_to vuelva a tomar el valor default
   * usuario1@company.com desde SetTrigger o SetBase.
   */
  const resolvedEmailTo = normalizeEmail(itemJson.email_to)
    || normalizeEmail(itemJson.agent_email)
    || '';

  data.email_to = resolvedEmailTo;
  data.agent_email = normalizeEmail(itemJson.agent_email) || data.agent_email || '';
  data.agent_name = itemJson.agent_name || data.agent_name || '';

  /*
   * Si no hay destinatario real, se marca el envÃ­o como deshabilitado.
   * Esto evita envÃ­os accidentales a correos default.
   */
  if (!data.email_to) {
    data.send_email = false;
    data.flags = {
      ...(data.flags || {}),
      send_email: false,
    };
  }

  const includeAttachment = flagEnabled(data, 'include_attachment', true);
  const binary = includeAttachment ? item.binary || {} : {};

  const html = repairMailEncoding(
    applyVisualFlags(data.html, data),
    false,
  );

  data.email_subject = repairMailEncoding(data.email_subject, true);

  return {
    json: {
      ...data,
      html,
      include_attachment_effective: includeAttachment,
      attachment_binary_names: includeAttachment && binary.csv ? 'csv' : '',
      has_csv_binary: Boolean(binary.csv),

      /*
       * Campos de auditorÃ­a temporal.
       * Puedes eliminarlos despuÃ©s de validar.
       */
      debug_email_to_from_item: itemJson.email_to || '',
      debug_agent_email_from_item: itemJson.agent_email || '',
      debug_email_to_final: data.email_to || '',
    },
    binary,
  };
});

const item = $input.first();
const body = item?.json?.body || {};
const errors = [];

function text(name) {
  return String(body[name] ?? '').trim();
}

function positiveNumber(name) {
  const raw = body[name];
  if (raw === undefined || raw === null || raw === '') return false;
  const n = Number(raw);
  return Number.isFinite(n) && n > 0;
}

function validDateText(name) {
  const value = text(name);
  if (!value) return false;
  const parsed = new Date(value.replace(' ', 'T'));
  return !Number.isNaN(parsed.getTime());
}

function dateWindowState() {
  const hasStart = text('start_date').length > 0;
  const hasEnd = text('end_date').length > 0;
  if (!hasStart && !hasEnd) return { provided: false, valid: false };
  if (!hasStart || !hasEnd) return { provided: true, valid: false, error: 'start_date y end_date deben enviarse juntos.' };
  if (!validDateText('start_date') || !validDateText('end_date')) return { provided: true, valid: false, error: 'start_date y end_date deben ser fechas v\u00e1lidas.' };
  const start = new Date(text('start_date').replace(' ', 'T'));
  const end = new Date(text('end_date').replace(' ', 'T'));
  if (start > end) return { provided: true, valid: false, error: 'start_date no puede ser mayor que end_date.' };
  return { provided: true, valid: true };
}

if (!text('email_to')) {
  errors.push('email_to es obligatorio para llamadas webhook.');
}

const webhookPath = 'itsm-tickets-abiertos-agente';
const window = dateWindowState();

if (webhookPath === 'cmdb-movimientos-recientes-inventario') {
  const hasMovementDays = positiveNumber('movement_days');
  if (!hasMovementDays && !window.valid) {
    errors.push(window.error || 'Debe enviar movement_days positivo o la ventana start_date + end_date.');
  }
}

if (webhookPath === 'cmdb-activos-proximos-vencer-garantia') {
  if (!positiveNumber('warranty_warning_months')) {
    errors.push('warranty_warning_months es obligatorio y debe ser un numero mayor a 0.');
  }
}

if (webhookPath === 'itsm-tickets-sin-actualizacion-24h') {
  if (!positiveNumber('stale_threshold_hours')) {
    errors.push('stale_threshold_hours es obligatorio y debe ser un numero mayor a 0.');
  }
}

if (window.provided && !window.valid && webhookPath !== 'cmdb-movimientos-recientes-inventario') {
  errors.push(window.error || 'Ventana de fechas inv\u00e1lida.');
}

const valid = errors.length === 0;

return [{
  json: {
    ...(item.json || {}),
    webhook_contract: {
      valid,
      status_code: valid ? 202 : 400,
      message: valid ? 'Workflow accepted' : errors.join(' '),
      errors,
    },
  },
  binary: item.binary,
}];

